def report_categories(records, budgets=None):
    """Return (category, count, total, over_budget) rows, highest total first.

    ``budgets`` maps category -> budget amount; a category is flagged
    over_budget when its total exceeds its budget. Categories without a
    budget entry are never flagged.
    """
    budgets = budgets or {}
    counts = {}
    totals = {}
    for r in records:
        counts[r["category"]] = counts.get(r["category"], 0) + 1
        totals[r["category"]] = totals.get(r["category"], 0.0) + r["value"]
    ranked = sorted(totals.items(), key=lambda kv: (-kv[1], kv[0]))
    return [
        (category, counts[category], total, category in budgets and total > budgets[category])
        for category, total in ranked
    ]

